function login() {
  let une = source.getLoginInfoMap().get("用户名");
  let pwd = source.getLoginInfoMap().get("密码");

  if (une && pwd) {
    let url = source.key + '/login.php';
    let body = `LoginForm%5Busername%5D=${une}&LoginForm%5Bpassword%5D=${pwd}&action=login&jumpurl=http%3A%2F%2Fwww.xkushu.info%2F&usecookie=1&submit=%E7%99%BB%E5%BD%95`;
    let head = JSON.parse(source.header);
    var login = java.post(url, body, head).body();
  }

  source.putLoginHeader(login);
}

function clearLogin() {
  cookie.removeCookie(source.getKey());
  source.removeLoginHeader();
  java.longToast('清除成功！');
}

